                { kana: "かえします", kanji: "返します", romaji: "kaeshimasu", arti: "Berikan kembali, mengembalikan", ex: "かりたほんをかえします。", ex_romaji: "Karita hon wo kaeshimasu.", ex_id: "Mengembalikan buku yang dipinjam." },
                { kana: "ぬぎます", kanji: "脱ぎます", romaji: "nugimasu", arti: "Lepas (pakaian, sepatu, dll)", ex: "へやにはいるまえにくつをぬぎます。", ex_romaji: "Heya ni hairu mae ni kutsu wo nugimasu.", ex_id: "Melepas sepatu sebelum masuk kamar." },
                { kana: "もっていきます", kanji: "持って行きます", romaji: "moっteikimasu", arti: "Mengambil dan bawa pergi sesuatu", ex: "かさをもっていきます。", ex_romaji: "Kasa wo motte ikimasu.", ex_id: "Membawa payung." },
                { kana: "もってきます", kanji: "持って来ます", romaji: "moっtekimasu", arti: "Membawa datang sesuatu", ex: "じしょをもってきてください。", ex_romaji: "Jisho wo motte kite kudasai.", ex_id: "Tolong bawa kamusnya." },
                { kana: "しんぱいします", kanji: "心配します", romaji: "shinpaishimasu", arti: "Mencemaskan", ex: "こどものことをしんぱいします。", ex_romaji: "Kodomo no koto wo shinpai shimasu.", ex_id: "Khawatir tentang anak." },
                { kana: "ざんぎょうします", kanji: "残業します", romaji: "zangyoushimasu", arti: "Lembur (kerja lembur)", ex: "きょうもざんぎょうしなければなりません。", ex_romaji: "Kyou mo zangyou shinakereba narimasen.", ex_id: "Hari ini juga harus lembur." },
                { kana: "しゅっちょうします", kanji: "出張します", romaji: "shuっchoushimasu", arti: "Melakukan perjalanan bisnis", ex: "らいしゅうおおさかにしゅっちょうします。", ex_romaji: "Raishuu Oosaka ni shucchou shimasu.", ex_id: "Minggu depan dinas ke Osaka." },
                { kana: "くすりをのみます", kanji: "薬を飲みます", romaji: "kusuriwonomimasu", arti: "Minum obat", ex: "ねるまえにくすりをのみます。", ex_romaji: "Neru mae ni kusuri wo nomimasu.", ex_id: "Minum obat sebelum tidur." },
                { kana: "おふろにはいります", kanji: "おふろに入ります", romaji: "ofuronihairimasu", arti: "Mandi (mandi di ofuro)", ex: "まいばんおふろにはいります。", ex_romaji: "Maiban ofuro ni hairimasu.", ex_id: "Setiap malam mandi di bak mandi." },
                { kana: "たいせつ", kanji: "大切", romaji: "taisetsu", arti: "Penting", ex: "けんこうはたいせつです。", ex_romaji: "Kenkou wa taisetsu desu.", ex_id: "Kesehatan itu penting." },
                { kana: "だいじょうぶ", kanji: "大丈夫", romaji: "daijoubu", arti: "Tidak apa-apa", ex: "だいじょうぶですか。けがはありませんか。", ex_romaji: "Daijoubu desu ka. Kega wa arimasen ka.", ex_id: "Tidak apa-apa? Tidak ada yang terluka?" },
                { kana: "あぶない", kanji: "危ない", romaji: "abunai", arti: "Bahaya", ex: "あぶない！くるまにきをつけて！", ex_romaji: "Abunai! Kuruma ni ki wo tsukete!", ex_id: "Bahaya! Hati-hati dengan mobil!" },
                { kana: "もんだい", kanji: "問題", romaji: "mondai", arti: "Masalah", ex: "なにかもんだいがありますか。", ex_romaji: "Nanika mondai ga arimasu ka.", ex_id: "Apakah ada masalah?" },
                { kana: "こたえ", kanji: "答え", romaji: "kotae", arti: "Jawaban", ex: "このもんだいのこたえはなんですか。", ex_romaji: "Kono mondai no kotae wa nan desu ka.", ex_id: "Apa jawaban dari soal ini?" },
                { kana: "きんえん", kanji: "禁煙", romaji: "kinen", arti: "Dilarang merokok", ex: "ここはきんえんです。", ex_romaji: "Koko wa kin-en desu.", ex_id: "Di sini dilarang merokok." },
                { kana: "びょうき", kanji: "病気", romaji: "biょuki", arti: "Sakit", ex: "びょうきでかいしゃをやすみます。", ex_romaji: "Byouki de kaisha wo yasumimasu.", ex_id: "Tidak masuk kantor karena sakit." },
                { kana: "くすり", kanji: "薬", romaji: "kusuri", arti: "Obat", ex: "くすりをのんでください。", ex_romaji: "Kusuri wo nonde kudasai.", ex_id: "Tolong minum obatnya." },
                { kana: "おふろ", kanji: "", romaji: "ofuro", arti: "Bak mandi", ex: "おふろにゆっくりつかります。", ex_romaji: "Ofuro ni yukkuri tsukarimasu.", ex_id: "Berendam santai di bak mandi." },
                { kana: "したぎ", kanji: "下着", romaji: "shitagi", arti: "Pakaian dalam", ex: "したぎをかえます。", ex_romaji: "Shitagi wo kaemasu.", ex_id: "Ganti pakaian dalam." },
                { kana: "どうしましたか", kanji: "", romaji: "doushimashitaka", arti: "Apa masalahnya?", ex: "どうしましたか。かおいろがわるいですよ。", ex_romaji: "Dou shimashita ka. Kaoiro ga warui desu yo.", ex_id: "Ada apa? Wajah Anda pucat." },
                { kana: "〜がいたいです", kanji: "〜が痛いです", romaji: "~gaitaidesu", arti: "Ada rasa sakit di ~ saya", ex: "のどがいたいです。", ex_romaji: "Nodo ga itai desu.", ex_id: "Tenggorokan sakit." },
                { kana: "ひきます", kanji: "弾きます", romaji: "hikimasu", arti: "Bermain (alat musik dawai atau piano, dll.)", ex: "このドアはひいてあけます。", ex_romaji: "Kono doa wa hiite akemasu.", ex_id: "Pintu ini dibuka dengan ditarik." },
                { kana: "うたいます", kanji: "歌います", romaji: "utaimasu", arti: "Bernyanyi", ex: "カラオケでうたいます。", ex_romaji: "Karaoke de utaimasu.", ex_id: "Bernyanyi di karaoke." },
                { kana: "あつめます", kanji: "集めます", romaji: "atsumemasu", arti: "Kumpulkan", ex: "きってをあつめています。", ex_romaji: "Kitte wo atsumete imasu.", ex_id: "Mengoleksi perangko." },
                { kana: "すてます", kanji: "捨てます", romaji: "sutemasu", arti: "Membuang", ex: "ごみをすてます。", ex_romaji: "Gomi wo sutemasu.", ex_id: "Membuang sampah." },
                { kana: "かえます", kanji: "換えます", romaji: "kaemasu", arti: "Menukar, ubah", ex: "パスワードをかえます。", ex_romaji: "Pasuwaado wo kaemasu.", ex_id: "Mengganti kata sandi." },
                { kana: "うんてんします", kanji: "運転します", romaji: "untenshimasu", arti: "Mengemudi", ex: "まいにちくるまをうんてんします。", ex_romaji: "Mainichi kuruma wo unten shimasu.", ex_id: "Setiap hari mengemudi mobil." },
                { kana: "よやくします", kanji: "予約します", romaji: "yoyakushimasu", arti: "Membooking tempat", ex: "レストランをよやくします。", ex_romaji: "Resutoran wo yoyaku shimasu.", ex_id: "Memesan tempat di restoran." },
                { kana: "けんがくします", kanji: "見学します", romaji: "kengakushimasu", arti: "Mengunjungi beberapa tempat untuk studi", ex: "こうじょうをけんがくします。", ex_romaji: "Koujou wo kengaku shimasu.", ex_id: "Mengunjungi pabrik untuk studi." },
                { kana: "ピアノ", kanji: "", romaji: "ピアノ", arti: "Piano", ex: "むすめはまいにちピアノをれんしゅうします。", ex_romaji: "Musume wa mainichi piano wo renshuu shimasu.", ex_id: "Putri saya setiap hari berlatih piano." },
                { kana: "こくさい〜", kanji: "国際〜", romaji: "kokusai~", arti: "Internasional ~", ex: "こくさいかいぎがとうきょうであります。", ex_romaji: "Kokusai kaigi ga Toukyou de arimasu.", ex_id: "Ada konferensi internasional di Tokyo." },
                { kana: "げんきん", kanji: "現金", romaji: "genkin", arti: "Uang tunai", ex: "げんきんではらいます。", ex_romaji: "Genkin de haraimasu.", ex_id: "Membayar dengan uang tunai." },
                { kana: "にっき", kanji: "日記", romaji: "niっki", arti: "Buku diari", ex: "まいばんにっきをかきます。", ex_romaji: "Maiban nikki wo kakimasu.", ex_id: "Setiap malam menulis diari." },
                { kana: "[お]いのり", kanji: "[お]祈り", romaji: "[o]inori", arti: "Berdoa", ex: "まいあさおいのりをします。", ex_romaji: "Maiasa ooinori wo shimasu.", ex_id: "Setiap pagi berdoa." },
                { kana: "かちょう", kanji: "課長", romaji: "kachou", arti: "Kepala Seksi", ex: "かちょうにほうこくします。", ex_romaji: "Kachou ni houkoku shimasu.", ex_id: "Melaporkan kepada kepala seksi." },
                { kana: "それはおもしろいですね。", kanji: "", romaji: "sorehaomoshiroidesune。", arti: "Itu pasti menarik.", ex: "それはおもしろいですね。くわしくはなしてください。", ex_romaji: "Sore wa omoshiroi desu ne. Kuwashiku hanashite kudasai.", ex_id: "Itu menarik ya. Tolong ceritakan lebih detail." },
                { kana: "ほんとうですか。", kanji: "", romaji: "hontoudesuka。", arti: "Benarkah begitu", ex: "ほんとうですか。しんじられません。", ex_romaji: "Hontou desu ka. Shinjiraramasen.", ex_id: "Benarkah? Tidak percaya." },
                { kana: "そうじします", kanji: "掃除します", romaji: "soujishimasu", arti: "Membersihkan (kamar/ruangan)", ex: "まいにちへやをそうじします。", ex_romaji: "Mainichi heya wo souji shimasu.", ex_id: "Setiap hari membersihkan kamar." },
                { kana: "せんたくします", kanji: "洗濯します", romaji: "sentakushimasu", arti: "Mencuci (pakaian)", ex: "まいしゅうどようびにせんたくします。", ex_romaji: "Maishuu doyoubi ni sentaku shimasu.", ex_id: "Setiap minggu mencuci pakaian hari Sabtu." },
                { kana: "れんしゅうします", kanji: "練習します", romaji: "renshuushimasu", arti: "Latihan", ex: "まいにちにほんごをれんしゅうします。", ex_romaji: "Mainichi Nihongo wo renshuu shimasu.", ex_id: "Setiap hari berlatih bahasa Jepang." },
                { kana: "なります", kanji: "", romaji: "narimasu", arti: "Menjadi", ex: "にほんごがうまくなりたいです。", ex_romaji: "Nihongo ga umaku naritai desu.", ex_id: "Ingin menjadi pandai bahasa Jepang." },
                { kana: "ねむい", kanji: "眠い", romaji: "nemui", arti: "Mengantuk", ex: "ゆうべよくねられなくて、ねむいです。", ex_romaji: "Yuube yoku nerarenakute, nemui desu.", ex_id: "Semalam kurang tidur, jadi mengantuk." },
                { kana: "ちょうしがいい", kanji: "調子がいい", romaji: "choushigaii", arti: "Berada dalam kondisi baik", ex: "きょうはちょうしがいいです。", ex_romaji: "Kyou wa choushi ga ii desu.", ex_id: "Hari ini kondisinya bagus." },
                { kana: "ちょうしがわるい", kanji: "調子が悪い", romaji: "choushigawarui", arti: "Berada dalam kondisi kurang baik", ex: "くるまのちょうしがわるいです。", ex_romaji: "Kuruma no choushi ga warui desu.", ex_id: "Kondisi mobil kurang baik." },
                { kana: "ちょうし", kanji: "調子", romaji: "choushi", arti: "Kondisi", ex: "からだのちょうしはどうですか。", ex_romaji: "Karada no choushi wa dou desu ka.", ex_id: "Bagaimana kondisi tubuh?" },
                { kana: "いちど", kanji: "", romaji: "ichido", arti: "Sekali", ex: "いちどにほんにいきたいです。", ex_romaji: "Ichido Nihon ni ikitai desu.", ex_id: "Ingin pergi ke Jepang sekali." },
                { kana: "いちども", kanji: "", romaji: "ichidomo", arti: "Tidak sekali, tidak pernah (digunakan dengan negatif)", ex: "かれはいちどもにほんにいったことがありません。", ex_romaji: "Kare wa ichido mo Nihon ni itta koto ga arimasen.", ex_id: "Dia belum pernah pergi ke Jepang sama sekali." },
                { kana: "もうすぐ", kanji: "", romaji: "mousugu", arti: "Segera", ex: "もうすぐなつです。", ex_romaji: "Mou sugu natsu desu.", ex_id: "Sebentar lagi musim panas." },
                { kana: "じつは", kanji: "実は", romaji: "jitsuha", arti: "Sebenarnya (untuk mengatakan yang sebenarnya)", ex: "じつは、にほんごがすきなんです。", ex_romaji: "Jitsu wa, Nihongo ga suki nan desu.", ex_id: "Sebenarnya, saya suka bahasa Jepang." },
                { kana: "ダイエット", kanji: "", romaji: "ダイエット", arti: "Diet", ex: "いまダイエットちゅうです。", ex_romaji: "Ima daietto chuu desu.", ex_id: "Sekarang sedang diet." },
                { kana: "なんかいも", kanji: "何回も", romaji: "nankaimo", arti: "Berkali-kali, berulang kali", ex: "このえいがをなんかいもみました。", ex_romaji: "Kono eiga wo nankai mo mimashita.", ex_id: "Sudah menonton film ini berkali-kali." },
                { kana: "しかし", kanji: "", romaji: "shikashi", arti: "Tetapi, tapi, bagaimanapun", ex: "べんきょうしました。しかし、しけんはむずかしかったです。", ex_romaji: "Benkyou shimashita. Shikashi, shiken wa muzukashikatta desu.", ex_id: "Sudah belajar. Tapi ujiannya susah." },
                { kana: "むり[な]", kanji: "無理[な]", romaji: "muri[na]", arti: "Berlebihan, tidak mungkin", ex: "そのしけんはむりです。", ex_romaji: "Sono shiken wa muri desu.", ex_id: "Ujian itu tidak mungkin." },
                { kana: "からだにいい", kanji: "体にいい", romaji: "karadaniii", arti: "Baik untuk kesehatan seseorang", ex: "やさいはからだにいいです。", ex_romaji: "Yasai wa karada ni ii desu.", ex_id: "Sayur baik untuk tubuh." },
                { kana: "いります", kanji: "要る", romaji: "irimasu", arti: "Membutuhkan, memerlukan [visa]", ex: "にほんにいくにはビザがいります。", ex_romaji: "Nihon ni iku ni wa biza ga irimasu.", ex_id: "Untuk pergi ke Jepang butuh visa." },
                { kana: "しゅうりします", kanji: "修理します", romaji: "shuurishimasu", arti: "Memperbaiki", ex: "じてんしゃをしゅうりします。", ex_romaji: "Jitensha wo shuuri shimasu.", ex_id: "Memperbaiki sepeda." },
                { kana: "でんわします", kanji: "電話します", romaji: "denwashimasu", arti: "Menelpon", ex: "あとでまたでんわします。", ex_romaji: "Atode mata denwa shimasu.", ex_id: "Nanti telepon lagi." }
