// KANA HELPERS
// ═══════════════════════════════════════════════════════════
function kanaGetCards(script, cats) {
    let out = [];
    const scripts = script === 'both' ? ['hiragana','katakana'] : [script];
    scripts.forEach(s => {
        Object.entries(KANA_D[s]).forEach(([cat, items]) => {
            if (cats[cat]) out.push(...items.map(x => ({...x, script: s, cat})));
        });
    });
    return out;
}
function kanaIsMastered(prog, c) {
    const p = prog[c];
    if (!p || p.seen < 3) return false;
    // FIX v3.0.9: lifetime ratio could get permanently "stuck" below 70%
    // because of a few wrong answers early on, even after the user has
    // since answered correctly many times in a row. A streak of 3+
    // consecutive correct answers (tracked in p.streak) also counts as
    // mastered, so recent improvement is reflected immediately.
    if ((p.streak || 0) >= 3) return true;
    return (p.correct / p.seen) >= 0.7;
}
// v3.0.11: A kana is considered "hafal" (memorized) if it's either
// manually marked as such via the flashcard "Sudah Hafal" toggle,
// or automatically detected as mastered through quiz performance.
function kanaIsHafal(c) {
    if (STATE.kanaHafal && STATE.kanaHafal[c]) return true;
    return kanaIsMastered(STATE.kanaProg, c);
}
function shuffle(arr) {
    const a = [...arr];
    for (let i = a.length-1; i > 0; i--) {
        const j = Math.floor(Math.random()*(i+1));
        [a[i],a[j]] = [a[j],a[i]];
    }
    return a;
}

